head.script:
 // 전역 변수 
scwin.userId = $c.data.getMemInfo("userId");
console.log("scwin.userId = " + scwin.userId);
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strPreDate = $c.date.addDate(scwin.strCurDate, -2);

scwin.params = $c.data.getParameter();
scwin.p_linkcheck = scwin.params.linkcheck;	 //  0:default,1:Booking Search,2:House Search,3:Master Search,4: Booking,5:House,6:master
scwin.p_kcomcd = scwin.params.kcomcd;
scwin.p_blno = scwin.params.blno;
scwin.p_mhno = scwin.params.mhno;
scwin.p_bkno = scwin.params.bkno;

scwin.statusFlag = "";	//수정/등록 Flag(C:Regist, U:Update,I:Init)
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.tabNo = 0;
scwin.mhnoFlag = "0"; // 1일때 mhno onloadComplete후 조회.

scwin.v_linkcheck = scwin.p_linkcheck;
scwin.v_kcomcd = scwin.p_kcomcd;
scwin.v_blno = scwin.p_blno;
scwin.v_mhno = scwin.p_mhno;
scwin.v_bkno = scwin.p_bkno;

//<!-- House BL조회 확인   -->
scwin.hd_kcomcd = "DBEX";

scwin.E_MSG_CM_INF_001 = "성공적으로 저장하였습니다.";
//---------------------------------------------------------
// 화면로딩시
//---------------------------------------------------------
scwin.onpageload = function () {

};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    scwin.f_initSetTab(); //tab세팅	

    if (acb_cnd_lc_seaAir.getValue() == "A") {
        scwin.f_BltypeDisable();
    } else {
        scwin.f_BltypeEnable();
    }

    scwin.f_Tab1Loading()
    $c.gus.cfDisableObjects([cbx_sub]);

    scwin.f_DefaultValue();
    scwin.f_Check();
    scwin.getMaxCloseYm(); //마감년월 가져오기
};


//---------------------------------------------------------
// Object Check
//---------------------------------------------------------
scwin.f_Check = function () {    
    acb_cnd_lc_seaAir.setSelectedIndex(0);
    acb_cnd_lc_iogb.setSelectedIndex(0);
    acb_cnd_lc_gbDate.setSelectedIndex(0);
    ed_cnd_ed_resultDtFrom.setValue(scwin.strPreDate);
    ed_cnd_ed_resultDtTo.setValue(scwin.strCurDate);
    rd_cnd_lc_totalTab1.setValue("S");
    rd_cnd_lc_totalTab2.setValue("S");
    acb_cnd_lc_kindTab1.setSelectedIndex(0);
    acb_cnd_lc_kindTab2.setSelectedIndex(0);
    acb_cnd_lc_blType.setSelectedIndex(0);

    acb_cnd_lc_seaAir.focus();

};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    scwin.f_Set("INIT")
};

//------------------z---------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
    $c.gus.cfDisableObjects([$c.global.tab_center0, $c.global.tab_center1, $c.global.tab_center2]);
//    tabControl2.setSelectedTabIndex(0);
};

//-------------------------------------------------------------------------
// f_EtdDisplay
//-------------------------------------------------------------------------		
scwin.f_BltypeDisable = function () {
    tbx_gubun1.show('none');             // B/L Type
    acb_cnd_lc_blType.show('none');      // cnd_lc_blType
}

//-------------------------------------------------------------------------
// f_EtaDisplay
//-------------------------------------------------------------------------		
scwin.f_BltypeEnable = function () {
    tbx_gubun1.show("");
    acb_cnd_lc_blType.show("");
}


//---------------------------------------------------------
// Tab Menu 선택시 처리
//---------------------------------------------------------
scwin.f_selectTabMenu = function (tabId, index) {
    var idx = index;
    console.log("f_selectTabMenu tabId,index = " + tabId + " : " + index);
//debugger;
    switch (idx) {
        case 0: //Main tab
            scwin.tabNo = 0;
            scwin.f_TotalGroupChange();
            scwin.f_Tab1Loading();
            $c.gus.cfEnableObjects([acb_cnd_lc_gbDate, ed_cnd_ed_linerCd, ed_cnd_ed_linerNm, ed_cnd_ed_salesCd1, ed_cnd_ed_salesCd2, ed_cnd_ed_salesCd3, ed_cnd_ed_picCd,
                ed_cnd_txt_salesNm1, ed_cnd_txt_salesNm2, ed_cnd_txt_salesNm3, ed_cnd_txt_picNm, ed_cnd_ed_pnCd, ed_cnd_txt_pnNm,
                ed_cnd_ed_arCd, ed_cnd_txt_arNm, ed_cnd_ed_cntyCd, ed_cnd_txt_cntyNm, ed_cnd_ed_loadCd, ed_cnd_txt_loadNm, ed_cnd_ed_discCd,
                ed_cnd_txt_discNm, rd_cnd_lc_totalTab1, rd_cnd_lc_totalTab2, acb_cnd_lc_kindTab1, acb_cnd_lc_kindTab2]);
            cbx_sub.setValue("");
            $c.gus.cfDisableObjects([cbx_sub]);
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                ed_cnd_ed_picCd.setValue("");
                ed_cnd_txt_picNm.setValue("");
                $c.gus.cfDisableObjects([ed_cnd_ed_picCd, ed_cnd_txt_picNm]);
            } else {
                $c.gus.cfEnableObjects([ed_cnd_ed_picCd, ed_cnd_txt_picNm]);
            }
            break

        case 1: //물동량
            scwin.tabNo = 1;
            scwin.f_TotalGroupChange();
            scwin.f_Tab2Loading();
            $c.gus.cfEnableObjects([acb_cnd_lc_gbDate, ed_cnd_ed_linerCd, ed_cnd_ed_linerNm, ed_cnd_ed_salesCd1, ed_cnd_ed_salesCd2, ed_cnd_ed_salesCd3,
                ed_cnd_txt_salesNm1, ed_cnd_txt_salesNm2, ed_cnd_txt_salesNm3, ed_cnd_ed_pnCd, ed_cnd_txt_pnNm,
                ed_cnd_ed_arCd, ed_cnd_txt_arNm, ed_cnd_ed_cntyCd, ed_cnd_txt_cntyNm, ed_cnd_ed_loadCd, ed_cnd_txt_loadNm, ed_cnd_ed_discCd,
                ed_cnd_txt_discNm, rd_cnd_lc_totalTab1, rd_cnd_lc_totalTab2, acb_cnd_lc_kindTab1, acb_cnd_lc_kindTab2]);
            cbx_sub.setValue("");
            $c.gus.cfDisableObjects([cbx_sub, ed_cnd_ed_picCd, ed_cnd_txt_picNm]);
            break;

        case 2: //월마감
            scwin.tabNo = 2;

            $c.gus.cfDisableObjects([acb_cnd_lc_gbDate, ed_cnd_ed_linerCd, ed_cnd_ed_linerNm, ed_cnd_ed_salesCd1, ed_cnd_ed_salesCd2, ed_cnd_ed_salesCd3, ed_cnd_ed_picCd,
                ed_cnd_txt_salesNm1, ed_cnd_txt_salesNm2, ed_cnd_txt_salesNm3, ed_cnd_txt_picNm, ed_cnd_ed_pnCd, ed_cnd_txt_pnNm,
                ed_cnd_ed_arCd, ed_cnd_txt_arNm, ed_cnd_ed_cntyCd, ed_cnd_txt_cntyNm, ed_cnd_ed_loadCd, ed_cnd_txt_loadNm, ed_cnd_ed_discCd,
                ed_cnd_txt_discNm, rd_cnd_lc_totalTab1, rd_cnd_lc_totalTab2, acb_cnd_lc_kindTab1, acb_cnd_lc_kindTab2]);

            $c.gus.cfEnableObjects([cbx_sub]);
            cbx_sub.setValue("1");
            scwin.f_CreateDateTime();
            break;
    }

    // cfViewTab(idx);
};

// 전월 마감여부 
scwin.getMaxCloseYm = function() {

    ds_search2.set('coCd','000');

     $c.sbm.execute(sbm_getMaxCloseYm);
};


//-------------------------------------------------------------------------
// f_EtdDisplay
//-------------------------------------------------------------------------		
scwin.f_Tab1Loading = function () {
    tbx_gubunTab1.show("");  // Total
    rd_cnd_lc_totalTab1.show("");  // rd_cnd_lc_totalTab1
    rd_cnd_lc_totalTab2.show("none");	// rd_cnd_lc_totalTab2		
    tbx_gubunTab4.show("");  // Group
    acb_cnd_lc_kindTab1.show("");	// acb_cnd_lc_kindTab1	
    acb_cnd_lc_kindTab2.show("none");	// acb_cnd_lc_kindTab2
    acb_cnd_lc_kindTab1.setSelectedIndex(0);
}

//-------------------------------------------------------------------------
// f_EtaDisplay
//-------------------------------------------------------------------------		
scwin.f_Tab2Loading = function () {
    tbx_gubunTab1.show();
    rd_cnd_lc_totalTab1.show("none");
    rd_cnd_lc_totalTab2.show("");
    tbx_gubunTab4.show("");
    acb_cnd_lc_kindTab1.show("none");
    acb_cnd_lc_kindTab2.show("");
    acb_cnd_lc_kindTab2.setSelectedIndex(0);
}


//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": //초기화
            if (scwin.tabNo == "0") { // tab1    		
                statusFlag = "I";
            } else if (scwin.tabNo == "1") {		// tab2  
                statusFlag = "I";
            }
            break;

        case "RETRIEVE":  //조회모드	
            if (scwin.tabNo == "0") { // tab1   			            	
                statusFlag = "";	 // flag null 
            } else if (scwin.tabNo == "1") {		// tab2          	
                statusFlag = "";	 // flag null 			
            }
            break;

        case "SAVE":
            if (scwin.tabNo == "0") { // tab1   	        	
                scwin.f_Set("RETRIEVE");
            } else if (scwin.tabNo == "1") {		// tab2
                scwin.f_Set("RETRIEVE");
            }
            break;
    }

};


//---------------------------------------------------------
// 조회 조건 지우기
//---------------------------------------------------------
scwin.f_FieldClear = function (e) {
    acb_cnd_lc_seaAir.setSelectedIndex(2);
    acb_cnd_lc_iogb.setSelectedIndex(1);
    acb_cnd_lc_gbDate.setSelectedIndex(0);
    ed_cnd_ed_resultDtFrom.setValue(scwin.strPreDate);
    ed_cnd_ed_resultDtTo.setValue(scwin.strCurDate);
    rd_cnd_lc_totalTab1.setValue("S");
    rd_cnd_lc_totalTab2.setValue("S");
    acb_cnd_lc_kindTab1.setSelectedIndex(0);
    acb_cnd_lc_kindTab2.setSelectedIndex(0);
    acb_cnd_lc_blType.setSelectedIndex(0);

    $c.gus.cfInitObjects([ed_cnd_ed_custCd, ed_cnd_txt_custNm,
        ed_cnd_ed_linerCd, ed_cnd_ed_linerNm,
        ed_cnd_ed_salesCd1, ed_cnd_txt_salesNm1,
        ed_cnd_ed_salesCd2, ed_cnd_txt_salesNm2,
        ed_cnd_ed_salesCd3, ed_cnd_txt_salesNm3,
        ed_cnd_ed_picCd, ed_cnd_txt_picNm,
        ed_cnd_ed_loadCd, ed_cnd_txt_loadNm,
        ed_cnd_ed_pnCd, ed_cnd_txt_pnNm,
        ed_cnd_ed_arCd, ed_cnd_txt_arNm,
        ed_cnd_ed_cntyCd, ed_cnd_txt_cntyNm,
        ed_cnd_ed_loadCd, ed_cnd_txt_loadNm,
        ed_cnd_ed_discCd, ed_cnd_txt_discNm,
        ed_cnd_ed_deptCd, ed_cnd_txt_deptNm]); // 조회조건의 테이블을 초기화.

    ds_performanceBiz.removeAll();
    ds_performanceOper.removeAll();

};

//---------------------------------------------------------
// 조회
//---------------------------------------------------------    

scwin.f_Retrieve = async function (e) {
    // VALIDATE
    let ret = await $c.gus.cfValidate([ed_cnd_ed_resultDtFrom, ed_cnd_ed_resultDtTo]);
    if (!ret) {  //validExp 가 yes일때 check
        return;
    }
//debugger;
/*
resultDtFrom
resultDtTo
*/

    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("inpid", scwin.userId);   
    ds_retrieve.set("resultDtFrom",ed_cnd_ed_resultDtFrom.getValue().replace('/',''));
    ds_retrieve.set("resultDtTo",ed_cnd_ed_resultDtTo.getValue().replace('/',''));
    // console.log("scwin.tabNo = " + scwin.tabNo)
    if (scwin.tabNo == "0") { // tab1
        if (acb_cnd_lc_kindTab1.getValue() == "1") {
            scwin.f_performanceBiz("1");
        } else if (acb_cnd_lc_kindTab1.getValue() == "2") {
            scwin.f_performanceBiz("2");
        } else if (acb_cnd_lc_kindTab1.getValue() == "3") {
            scwin.f_performanceBiz("3");
        } else if (acb_cnd_lc_kindTab1.getValue() == "4") {
            scwin.f_performanceBiz("4");
        } else if (acb_cnd_lc_kindTab1.getValue() == "5") {
            scwin.f_performanceBiz("5");
        } else if (acb_cnd_lc_kindTab1.getValue() == "6") {
            scwin.f_performanceBiz("6");
        } else if (acb_cnd_lc_kindTab1.getValue() == "7") {
            scwin.f_performanceBiz("7");
        } else if (acb_cnd_lc_kindTab1.getValue() == "8") {
            scwin.f_performanceBiz("8");
        } else if (acb_cnd_lc_kindTab1.getValue() == "9") {
            scwin.f_performanceBiz("9");
        } else {
            scwin.f_performanceBiz("10");
        }

        ds_retrieve.set("resultDtFrom",ds_retrieve.get("resultDtFrom").replace('/',''));
        ds_retrieve.set("resultDtTo",ds_retrieve.get("resultDtTo").replace('/',''));


        ds_retrieve.set("kind", acb_cnd_lc_kindTab1.getValue());
        ds_retrieve.set("flag", "1");
        $c.sbm.execute(sbm_retrieveBiz)
    } else if (scwin.tabNo == "1") {		// 물동량	
        if (acb_cnd_lc_kindTab2.getValue() == "1") {
            scwin.f_performanceOper("1");
        } else if (acb_cnd_lc_kindTab2.getValue() == "2") {
            scwin.f_performanceOper("2");
        } else if (acb_cnd_lc_kindTab2.getValue() == "3") {
            scwin.f_performanceOper("3");
        } else if (acb_cnd_lc_kindTab2.getValue() == "4") {
            scwin.f_performanceOper("4");
        } else {
            scwin.f_performanceOper("5");
        }

        ds_retrieve.set("resultDtFrom",ds_retrieve.get("resultDtFrom").replace('/',''));
        ds_retrieve.set("resultDtTo",ds_retrieve.get("resultDtTo").replace('/',''));
        ds_retrieve.set("kind", acb_cnd_lc_kindTab2.getValue());
        ds_retrieve.set("flag", "2");

        $c.sbm.execute(sbm_retrieveOper);
    } else if (scwin.tabNo == "2") {     // 월마감 

        ds_retrieve.set("resultDtFrom",ds_retrieve.get("resultDtFrom").replace('/',''));
        ds_retrieve.set("resultDtTo",ds_retrieve.get("resultDtTo").replace('/',''));
        ds_retrieve.set("flag", "3");

        gr_thirdForm.initGrid();

        $c.sbm.execute(sbm_retrieveThird);

//        await scwin.f_CreateDateTime();

    }


};

//-------------------------------------------------------------------------
//Selling unit 가져오기
//------------------------------------------------------------------------- 	
scwin.f_TotalGroupChange = function () {
    console.log("scwin.f_TotalGroupChange scwin.tabNo = " + scwin.tabNo + " : rd_cnd_lc_totalTab1.getValue() = " + rd_cnd_lc_totalTab1.getValue() + " : acb_cnd_lc_kindTab1.getValue() = " + acb_cnd_lc_kindTab1.getValue())

    if (scwin.tabNo == "0") { // tab1  
        if (rd_cnd_lc_totalTab1.getValue() == "S") {
            ed_cnd_ed_picCd.setValue("");
            ed_cnd_txt_picNm.setValue("");
            $c.gus.cfDisableObjects([ed_cnd_ed_picCd, ed_cnd_txt_picNm]);
        } else {
            $c.gus.cfEnableObjects([ed_cnd_ed_picCd, ed_cnd_txt_picNm]);
        }

        if (acb_cnd_lc_kindTab1.getValue() == "1") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("1");
            } else {
                scwin.f_gridFormatBiz("2");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "2") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("3");
            } else {
                scwin.f_gridFormatBiz("4");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "3") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("5");
            } else {
                scwin.f_gridFormatBiz("6");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "4") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("7");
            } else {
                scwin.f_gridFormatBiz("8");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "5") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("9");
            } else {
                scwin.f_gridFormatBiz("10");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "6") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("11");
            } else {
                scwin.f_gridFormatBiz("12");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "7") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("13");
            } else {
                scwin.f_gridFormatBiz("14");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "8") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("15");
            } else {
                scwin.f_gridFormatBiz("16");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "9") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("17");
            } else {
                scwin.f_gridFormatBiz("18");
            }
        } else if (acb_cnd_lc_kindTab1.getValue() == "10") {
            if (rd_cnd_lc_totalTab1.getValue() == "S") {
                scwin.f_gridFormatBiz("19");
            } else {
                scwin.f_gridFormatBiz("20");
            }
        }
        ds_performanceBiz.removeAll();

    } else if (scwin.tabNo == "1") {		// tab2
        if (acb_cnd_lc_kindTab2.getValue() == "1") {
            if (rd_cnd_lc_totalTab2.getValue() == "S") {
                scwin.f_gridFormatOper("1");
            } else {
                scwin.f_gridFormatOper("2");
            }
        } else if (acb_cnd_lc_kindTab2.getValue() == "2") {
            if (rd_cnd_lc_totalTab2.getValue() == "S") {
                scwin.f_gridFormatOper("3");
            } else {
                scwin.f_gridFormatOper("4");
            }
        } else if (acb_cnd_lc_kindTab2.getValue() == "3") {
            if (rd_cnd_lc_totalTab2.getValue() == "S") {
                scwin.f_gridFormatOper("5");
            } else {
                scwin.f_gridFormatOper("6");
            }
        } else if (acb_cnd_lc_kindTab2.getValue() == "4") {
            if (rd_cnd_lc_totalTab2.getValue() == "S") {
                scwin.f_gridFormatOper("7");
            } else {
                scwin.f_gridFormatOper("8");
            }
        } else if (acb_cnd_lc_kindTab2.getValue() == "5") {
            if (rd_cnd_lc_totalTab2.getValue() == "S") {
                scwin.f_gridFormatOper("9");
            } else {
                scwin.f_gridFormatOper("10");
            }
        }
        ds_performanceOper.removeAll();
    }
};



//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_PopUp = function (disGubun, chgGubun) {

    var rtnList = new Array();
    switch (disGubun) {
        case "Customer":
            udc_custCd.setSelectId('retrieveEngClntInfo')
            udc_custCd.ilCommonPopUp(scwin.udc_custCd_callBackFunc,
                ed_cnd_ed_custCd.getValue().trim(),     // 화면에서의 ??? Code Element의	Value                                  
                ed_cnd_txt_custNm.getValue(), 			// 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭	                                               
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                "F",                            // 전체검색허용여부	("F")                                                  
                'Customer search,Customer Code,Customer Name');

            break;
        case "Partner":
            udc_pnCd.setSelectId('retrieveEngClntInfo')
            udc_pnCd.ilCommonPopUp(scwin.udc_pnCd_callBackFunc,
                ed_cnd_ed_pnCd.getValue().trim(),        // 화면에서의 ??? Code Element의	Value                                  
                ed_cnd_txt_pnNm.getValue(),             // 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭	                                               
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정	                                       
