            , sheetName: sheetTitle //엑셀내 시트명 지정필요시
            , type: "2 + 4 + 8 + 16"
        };

        const infoArr = [];
        cfrm = await $c.win.confirm("Performance List" + sheetTitle + "를 EXCEL로 다운로드 받으시겠습니까?");
