        $c.win.alert(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.  

    }
};

scwin.f_downExcelSheetthirdForm = async function () {  
    let options =
    {   
        fileName: "월마감.xlsx"
        , sheetName: "월마감"
        , type: "2+4+8+16"
    };
    if (cbx_sub.getValue() == 0) {
        options.useSubTotal = "false";
    } else {
        options.useSubTotal = "true";
    }

    options.decimal = "auto";
    options.useDataFormat = "true";
    $c.data.downloadGridViewExcel(gr_thirdForm, options, []);
};

