scwin.f_performanceBiz = function (gubun1) {
    switch (gubun1) {
        case "1": // CUSTOMER,SUMMARY		 
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // RESULT,SUMMARY
                scwin.f_gridFormatBiz("1");
            } else {  						  // RESULT,DETAIL
                scwin.f_gridFormatBiz("2");
            }
            break;
        case "2": // CUSTOMER,SUMMARY		  							    	
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // CUSTOMER,SUMMARY
                scwin.f_gridFormatBiz("3");
            } else {  							// CUSTOMER,DETAIL
                scwin.f_gridFormatBiz("4");
            }
            break;
        case "3": // DEPARTMENT,SUMMARY		  							    	
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // DEPARTMENT,SUMMARY
                scwin.f_gridFormatBiz("5");
            } else {  							// DEPARTMENT,DETAIL
                scwin.f_gridFormatBiz("6");
            }
            break;
        case "4": // LINER,SUMMARY		  							    	
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // LINER,SUMMARY
                scwin.f_gridFormatBiz("7");
            } else {  							// LINER,DETAIL
                scwin.f_gridFormatBiz("8");
            }
            break;
        case "5": // PARTNER,SUMMARY		  							    	
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // PARTNER,SUMMARY
                scwin.f_gridFormatBiz("9");
            } else {  							// PARTNER,DETAIL
                scwin.f_gridFormatBiz("10");
            }
            break;
        case "6": // AREA,SUMMARY		  							    	
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // AREA,SUMMARY
                scwin.f_gridFormatBiz("11");
            } else {  							// AREA,DETAIL
                scwin.f_gridFormatBiz("12");
            }
            break;
        case "7": // COUNTRY,SUMMARY		  							    	
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // COUNTRY,SUMMARY
                scwin.f_gridFormatBiz("13");
            } else {  							// COUNTRY,DETAIL
                scwin.f_gridFormatBiz("14");
            }
            break;
        case "8": // LOADING,SUMMARY		  							    	
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // LOADING,SUMMARY
                scwin.f_gridFormatBiz("15");
            } else {  							// LOADING,DETAIL
                scwin.f_gridFormatBiz("16");
            }
            break;
        case "9": // DISCHARGE,SUMMARY		  							    	
            if (rd_cnd_lc_totalTab1.getValue() == "S") { // DISCHARGE,SUMMARY
                scwin.f_gridFormatBiz("17");
            } else {  							// DISCHARGE,DETAIL
