scwin.f_performanceOper = async function (gubun1) {
//debugger;    
    switch (gubun1) {
        case "1": // CUSTOMER
            if (rd_cnd_lc_totalTab2.getValue() == "S") { // CUSTOMER,SUMMARY	  			
                await scwin.f_gridFormatOper("1");
            } else {  							// CUSTOMER,월별	
