            if (rd_cnd_lc_totalTab2.getValue() == "S") { // DEPARTMENT,SUMMARY	  			
                await scwin.f_gridFormatOper("3");
            } else {  							// DEPARTMENT,월별	
                await scwin.f_gridFormatOper("4");
            }
            break;
        case "3": // LINER
            if (rd_cnd_lc_totalTab2.getValue() == "S") { // LINER,SUMMARY	  			
                await scwin.f_gridFormatOper("5");
            } else {  							// LINER,월별	
                await scwin.f_gridFormatOper("6");
            }
            break;
        case "4": // AREA
            if (rd_cnd_lc_totalTab2.getValue() == "S") { // AREA,SUMMARY	  			
                await scwin.f_gridFormatOper("7");
            } else {  							// AREA,월별	
                await scwin.f_gridFormatOper("8");
            }
            break;
        case "5": //PORT 
            if (rd_cnd_lc_totalTab2.getValue() == "S") { // PORT,SUMMARY	  			
               await scwin.f_gridFormatOper("9");
            } else {  							// PORT,월별	
               await scwin.f_gridFormatOper("10");
            }
            break;
    }
}

//---------------------------------------------------------
// Grid evert 처리 
//---------------------------------------------------------
scwin.f_gridFormatBiz = function (gubun1) {
    for (var i = 1; i <= 20; i++) {
//debugger;
        var gridId = "gr_performanceBiz" + i;
        var gridObj = $p.getComponentById(gridId);
        if (gubun1 == i) {
            if (gridObj){
                 gridObj.setStyle("display", "block");
                 gridObj.initGrid();
                 udcGrdBtn.setGridId(gridId);
            }
        } else {
            if (gridObj) gridObj.setStyle("display", "none");
        }
   //     udc_biz.setGridId(gridId);
    }
}

