};


//Selling unit 가져오기
scwin.f_houseBlLoadingBiz = function(Row) {
    var param1 = "";
    var param2 = "";
    var param3 = "";
    var param4 = "";	
    var param5 = "";
    var param6 = "";
    var param7 = "";
    var param8 = "";	
    var param9 = "";
    var param10 = "";
    var param11 = "";
    var param12 = "";	
    var param13 = "";
    var param14 = "";													

    param1 = cnd_lc_seaAir.BindColVal ;
    param2 = cnd_lc_iogb.BindColVal ;
    param3 = cnd_ed_resultDtFrom.Text ;
    param4 = cnd_ed_resultDtTo.Text ;

    if (cnd_lc_kindTab1.BindColVal == "1") {  // customer
        param5 = ds_performanceBiz.NameValue(Row, "vcol02");
    } else {
        param5 = ds_performanceBiz.NameValue(Row, "vcol04");		
    }

    param6 = cnd_ed_loadCd.Text ;
    param7 = cnd_txt_loadNm.value ;			
