scwin.ds_thirdForm_ondataload = function (e) {
    var rowcnt = ds_thirdForm.getRowCount();
    if (rowcnt > 0) {

        var options = {};
        if (cbx_sub.getValue() == "1") {
            options.sortIndex = "seaAir ioGb custCd resultMonth";
            options.sortOrder = "1 1 1 1";     //오른차순:"1", 내림차순"-1"
        } else if (cbx_sub.getValue() == "") {
            options.sortIndex = "seaAir ioGb resultMonth sellAmt";
            options.sortOrder = "1 1 1 -1";     //오른차순:"1", 내림차순"-1"
        }
        ds_thirdForm.multisort(options)
        ds_thirdForm.reform();

        tbx_totalRows3.setValue(rowcnt);
    } else {
        $c.win.alert("조회된 데이터가 없습니다.");
        return false;
    }
}


